package net.evarius.terranexus.management;

import net.evarius.terranexus.identity.AuthorityState;import net.minecraft.inventory.SimpleInventory;import net.minecraft.item.Items;import net.minecraft.screen.SimpleNamedScreenHandlerFactory;import net.minecraft.server.network.ServerPlayerEntity;import net.minecraft.text.Text;import net.minecraft.util.Formatting;import java.util.*;

public final class AdminDesktopScreen {
    private AdminDesktopScreen() {}
    public static void open(ServerPlayerEntity player){boolean identity=AuthorityState.mayManageIdentity(player),land=AuthorityState.mayUseLandOffice(player);if(!identity&&!land){player.sendMessage(Text.literal("Dieser Verwaltungs-PC ist nur für autorisierte Bedienstete freigeschaltet.").formatted(Formatting.RED),false);return;}SimpleInventory inventory=new SimpleInventory(54);Map<Integer,java.util.function.Consumer<net.minecraft.entity.player.PlayerEntity>> actions=new HashMap<>();ManagementHubScreen.display(inventory,4,Items.COMPARATOR,"TerraNexus Admin-Desktop","Vollständige Verwaltungsübersicht entsprechend deiner Rollen");if(identity){ManagementHubScreen.display(inventory,19,Items.WRITABLE_BOOK,"Bürger- und Einreiseverwaltung","Akten anlegen, bearbeiten und freischalten");actions.put(19,x->ImmigrationScreen.open(player));}ManagementHubScreen.display(inventory,21,Items.GOLD_INGOT,"Verwaltungsbank","Personen-, Institutions- und Gebietskonten");actions.put(21,x->EconomyScreen.open(player));ManagementHubScreen.display(inventory,23,Items.BRICKS,"Institutionen","Firmen, Behörden, Vereine und Gruppen");actions.put(23,x->InstitutionScreen.open(player));if(land){ManagementHubScreen.display(inventory,25,Items.FILLED_MAP,"Grundbuch und Landlord","Flächen, Kauf, Miete, Rechte und Gebiete");actions.put(25,x->PropertyScreen.open(player));}if(AuthorityState.mayAdministerLand(player)){ManagementHubScreen.display(inventory,31,Items.WRITABLE_BOOK,"Grundstücks-Audit","Persistente Änderungen und Eigentümerwechsel");actions.put(31,x->LandSearchScreen.audit(player));}player.openHandledScreen(new SimpleNamedScreenHandlerFactory((id,pi,x)->new ActionMenuScreenHandler(id,pi,inventory,actions),Text.literal("TerraNexus Admin-Desktop").formatted(Formatting.DARK_AQUA)));}
}
